class Solution:
    def nthMagicalNumber(self, n, a, b):
        MOD = 10 ** 9 + 7
        def gcd(x, y):
            while y:
                x, y = y, x % y
            return x
        g = gcd(a, b)
        lcm = b // g * a
        def count(x):
            return x // a + x // b - x // lcm
        hi = max(a, b)
        while count(hi) < n:
            hi *= 2
        lo = 1
        while lo < hi:
            mid = lo + (hi - lo) // 2
            if count(mid) < n:
                lo = mid + 1
            else:
                hi = mid
        return lo % MOD

