import math
class Solution:
    def nthMagicalNumber(self, n, a, b):
        MOD = 10 ** 9 + 7
        g = math.gcd(a, b)
        l = a // g * b
        lo, hi = 1, n * min(a, b)
        while lo < hi:
            mid = (lo + hi) // 2
            cnt = mid // a + mid // b - mid // l
            if cnt < n:
                lo = mid + 1
            else:
                hi = mid
        return lo % MOD

