var nthMagicalNumber = function(n, a, b) {
    function gcd(x, y) {
        while (y) {
            const t = y;
            y = x % y;
            x = t;
        }
        return x;
    }
    const MOD = 1000000007;
    const g = gcd(a, b);
    const l = (a / g) * b;
    let lo = 1, hi = n * Math.min(a, b);
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        const cnt = Math.floor(mid / a) + Math.floor(mid / b) - Math.floor(mid / l);
        if (cnt < n) lo = mid + 1;
        else hi = mid;
    }
    return lo % MOD;
};
